import { promises as fs } from "fs";

export async function doStep(step: number): Promise<void> {
  await fs.appendFile("/workspace/progress.log", `step ${step}\n`);
}

import { defineQuery, proxyActivities, setHandler, sleep } from "@temporalio/workflow";
import type * as activities from "./activities";

export interface ProgressInfo {
  progress: number;
  currentStep: number;
  total: number;
}

const { doStep } = proxyActivities<typeof activities>({
  startToCloseTimeout: "30s",
});

export async function ProgressWorkflow(totalSteps: number): Promise<ProgressInfo> {
  let progress = 0;
  let currentStep = 0;

  const getProgress = defineQuery<ProgressInfo>("getProgress");
  setHandler(getProgress, () => ({
    progress,
    currentStep,
    total: totalSteps,
  }));

  for (let step = 1; step <= totalSteps; step += 1) {
    await doStep(step);
    currentStep = step;
    progress = step / totalSteps;
    await sleep("1s");
  }

  return {
    progress,
    currentStep,
    total: totalSteps,
  };
}

import { Connection } from "@temporalio/client";
import { Worker } from "@temporalio/worker";
import path from "path";
import * as activities from "./activities";

const taskQueue = "progress-ts";

async function runWorker(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address || !apiKey || !namespace) {
    throw new Error("Missing TEMPORAL_ADDRESS, TEMPORAL_API_KEY, or TEMPORAL_NAMESPACE env vars");
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
    metadata: {
      "temporal-namespace": namespace,
    },
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue,
    workflowsPath: path.join(__dirname, "workflows"),
    activities,
  });

  await worker.run();
}

runWorker().catch((error) => {
  console.error(error);
  process.exit(1);
});

import { Connection, Client } from "@temporalio/client";
import { promises as fs } from "fs";
import path from "path";

const taskQueue = "progress-ts";

async function runClient(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !apiKey || !namespace) {
    throw new Error("Missing TEMPORAL_ADDRESS, TEMPORAL_API_KEY, or TEMPORAL_NAMESPACE env vars");
  }
  if (!runId) {
    throw new Error("Missing ZEALT_RUN_ID env var");
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
    metadata: {
      "temporal-namespace": namespace,
    },
  });

  const client = new Client({
    connection,
    namespace,
  });

  await fs.writeFile("/workspace/progress.log", "");

  const workflowId = `progress-${runId}`;
  const handle = await client.workflow.start("ProgressWorkflow", {
    workflowId,
    taskQueue,
    args: [5],
  });

  await new Promise((resolve) => {
    setTimeout(resolve, 2500);
  });

  const progress = await handle.query("getProgress");
  await fs.writeFile("/workspace/progress.json", JSON.stringify(progress, null, 2));

  const result = await handle.result();
  const resultPath = path.join("/workspace", "progress-result.json");
  await fs.writeFile(resultPath, JSON.stringify(result, null, 2));
}

runClient().catch((error) => {
  console.error(error);
  process.exit(1);
});

